-- 0006: 수료증 서식(JSON) DB 저장 + 발급번호 체계 변경(제YYYY-NNN호 전역 순차)
--
-- 1) certificate_templates — 첨부 수료증 서식 PDF를 JSON으로 변환해 저장.
--    이미지(GNU 테두리 프레임, 직인)는 base64 data URL로 원본 그대로 보존한다.
-- 2) certificates.issued_channel — 발급 경로(admin/public) 추적.
-- 3) issue_certificate RPC 교체 — 번호 체계를 '제YYYY-NNN호' 전역 순차로 변경하고,
--    공개 수료증 발급 탭(Edge Function, service role)에서도 호출할 수 있게 가드를 확장.

-- ============================================================================
-- 1) 수료증 서식 템플릿 테이블 (kakao_templates 패턴)
-- ============================================================================
create table if not exists public.certificate_templates (
  id uuid primary key default gen_random_uuid(),
  name text not null unique default 'default',
  template jsonb not null,
  updated_at timestamptz not null default now()
);

create trigger trg_certificate_templates_updated_at
  before update on public.certificate_templates
  for each row execute function public.set_updated_at();

alter table public.certificate_templates enable row level security;

-- 관리자 화면은 직접 조회, 공개 발급 탭은 Edge Function(service role)이 전달한다.
create policy "certificate_templates_admin_all" on public.certificate_templates
  for all using (public.is_admin()) with check (public.is_admin());

-- ============================================================================
-- 2) 발급 경로 추적 컬럼
-- ============================================================================
alter table public.certificates
  add column if not exists issued_channel text not null default 'admin'
  check (issued_channel in ('admin', 'public'));

-- ============================================================================
-- 3) issue_certificate 교체 — 시그니처 변경이므로 drop 후 재생성(같은 트랜잭션)
-- ============================================================================
drop function if exists public.issue_certificate(uuid);

create function public.issue_certificate(
  p_application_id uuid,
  p_channel text default 'admin'
) returns public.certificates
language plpgsql
security definer
set search_path = public
as $$
declare
  v_app public.applications%rowtype;
  v_existing public.certificates%rowtype;
  v_year text;
  v_serial int;
  v_cert_no text;
  v_result public.certificates%rowtype;
begin
  -- 관리자(브라우저 세션) 또는 service role(공개 발급 Edge Function)만 허용
  if not (public.is_admin() or coalesce(auth.jwt() ->> 'role', '') = 'service_role') then
    raise exception '관리자만 수료증을 발급할 수 있습니다.' using errcode = '42501';
  end if;

  if p_channel not in ('admin', 'public') then
    raise exception '잘못된 발급 채널입니다.';
  end if;

  select * into v_app from public.applications where id = p_application_id;
  if v_app.id is null then
    raise exception '신청 건을 찾을 수 없습니다.';
  end if;

  if v_app.status <> '이수' then
    raise exception '이수 상태인 신청 건만 수료증을 발급할 수 있습니다.';
  end if;

  v_year := to_char(now() at time zone 'Asia/Seoul', 'YYYY');

  -- 채번은 연도별 전역 순차 — 전역 잠금으로 동시 발급 충돌 방지
  perform pg_advisory_xact_lock(hashtext('cert_serial_' || v_year));

  select * into v_existing from public.certificates where application_id = p_application_id;

  if v_existing.id is not null then
    -- 재발급: 번호·채널 불변, 횟수만 증가
    update public.certificates
      set reissue_count = reissue_count + 1
      where id = v_existing.id
      returning * into v_result;
    return v_result;
  end if;

  -- 삭제 내성 채번: 현재 연도 형식(제YYYY-NNN호)의 최대 일련번호 + 1.
  -- 레거시(AI-2026-...) 번호는 정규식에 걸리지 않아 새 체계는 001부터 시작한다.
  select coalesce(max((regexp_match(cert_no, '^제' || v_year || '-(\d+)호$'))[1]::int), 0) + 1
    into v_serial
  from public.certificates
  where cert_no ~ ('^제' || v_year || '-\d+호$');

  v_cert_no := '제' || v_year || '-' || lpad(v_serial::text, 3, '0') || '호';

  insert into public.certificates (application_id, cert_no, issuer, issued_at, reissue_count, issued_channel)
  values (p_application_id, v_cert_no, '경상국립대학교 AI융합원장', now(), 0, p_channel)
  returning * into v_result;

  update public.applications set cert_issued = true where id = p_application_id;

  return v_result;
end;
$$;

grant execute on function public.issue_certificate(uuid, text) to authenticated, service_role;

-- ============================================================================
-- 4) 서식 JSON 시드 (첨부 수료증서식.pdf에서 변환 — 이미지·문구·좌표 보존)
-- ============================================================================
insert into public.certificate_templates (name, template)
values ('default', $tpl${"version":1,"page":{"width":595.28,"height":841.89},"images":[{"key":"frame","dataUrl":"data:image/jpeg;base64,","x":28.305,"y":34.043,"w":538.271,"h":778.668},{"key":"seal","dataUrl":"data:image/jpeg;base64,","x":418.215,"y":133.414,"w":95.948,"h":95.895}],"texts":[{"key":"certNo","text":"{발급번호}","x":80.7,"y":744.5,"size":15,"weight":"regular","align":"left"},{"key":"title","text":"수  료  증","y":649.7,"size":50,"weight":"bold","align":"center"},{"key":"nameL1","text":"성","x":83.6,"y":565.4,"size":16,"weight":"regular","align":"left"},{"key":"nameL2","text":"명","x":147.5,"y":565.4,"size":16,"weight":"regular","align":"left"},{"key":"nameC","text":":","x":163.5,"y":565.4,"size":16,"weight":"regular","align":"left"},{"key":"nameV","text":"{성명}","x":179.5,"y":565.4,"size":16,"weight":"regular","align":"left"},{"key":"affL1","text":"소","x":83.6,"y":539.9,"size":16,"weight":"regular","align":"left"},{"key":"affL2","text":"속","x":147.5,"y":539.9,"size":16,"weight":"regular","align":"left"},{"key":"affC","text":":","x":163.5,"y":539.9,"size":16,"weight":"regular","align":"left"},{"key":"affV","text":"{소속}","x":179.5,"y":539.9,"size":16,"weight":"regular","align":"left","maxWidth":330},{"key":"progL","text":"프로그램명","x":83.6,"y":514.3,"size":16,"weight":"regular","align":"left"},{"key":"progC","text":":","x":163.5,"y":514.3,"size":16,"weight":"regular","align":"left"},{"key":"progV","text":"{프로그램명}","x":179.5,"y":514.3,"size":16,"weight":"regular","align":"left","maxWidth":330},{"key":"periodL1","text":"기","x":83.6,"y":488.7,"size":16,"weight":"regular","align":"left"},{"key":"periodL2","text":"간","x":147.5,"y":488.7,"size":16,"weight":"regular","align":"left"},{"key":"periodC","text":":","x":163.5,"y":488.7,"size":16,"weight":"regular","align":"left"},{"key":"periodV","text":"{기간}","x":179.5,"y":488.7,"size":16,"weight":"regular","align":"left","maxWidth":330},{"key":"body1","text":"위 사람은 본 기관의 상기 교육과정을","y":402.8,"size":21,"weight":"regular","align":"center"},{"key":"body2","text":"수료하였으므로 이 증서를 수여 합니다.","y":365,"size":21,"weight":"regular","align":"center"},{"key":"issueDate","text":"{발급일}","y":274.1,"size":20,"weight":"regular","align":"center"},{"key":"issuer","text":"경상국립대학교 AI융합원장","y":170.6,"size":29,"weight":"bold","align":"center"}]}$tpl$::jsonb)
on conflict (name) do update set template = excluded.template;
